//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Sections & page setup (§17.6)".
//!
//! Each `#[test]` encodes a Word-consumption / OOXML-storage rule for section
//! properties (sectPr placement, page size/orientation, continuous breaks, and
//! column definitions). A FAILING assertion is NOT a flaky test to be muted: it
//! encodes a REAL Word-compliance gap in stemma (the engine diverges from what
//! ECMA-376 / ISO 29500 / MS-OI29500 say Word requires, stores, or reads). Do
//! not weaken an assertion to make it green — fix the engine or record the gap.
//!
//! Methodology note: stemma round-trips UNTOUCHED body content byte-verbatim, so
//! `reserialize()` of an unedited document reflects stemma's verbatim-preservation
//! contract, not Word's save-time normalization. The xml* expectations here are
//! therefore restricted to child/element ORDERING and structural placement that
//! the serializer actively governs; consumption semantics are asserted on the
//! read side (`read_accepted`/`read_rejected`), and validity via
//! `stemma::api::validate(..).ok`.

use std::io::Read as _;

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude / plumbing ──────────────────────────────────────────────────────

/// Build a valid minimal `.docx` whose `word/document.xml` body is `body_xml`
/// (wrapped in `<w:document ...><w:body>…</w:body></w:document>`).
///
/// `extra_parts` is a list of `(part_path, xml)` pairs (e.g.
/// `("word/styles.xml", "<w:styles…/>")`); each gets a `[Content_Types].xml`
/// override based on its filename so the package stays well-formed.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#,
    );

    // Content-type overrides for the known extra parts.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _) in extra_parts {
        let content_type = if path.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if path.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else if path.ends_with("settings.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.settings+xml"
        } else {
            panic!("make_docx: no content-type mapping for extra part {path}");
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{path}" ContentType="{content_type}"/>"#,
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#,
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip `docx` and return the contents of `word/document.xml`.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive =
        zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip archive");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present in archive");
    let mut out = String::new();
    file.read_to_string(&mut out)
        .expect("read word/document.xml");
    out
}

/// Parse `bytes`, re-serialize via stemma's default export, and return the
/// resulting `word/document.xml` string.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize for reserialize");
    document_xml_of(&out)
}

/// Remove whitespace that sits BETWEEN a `>` and a `<` (indentation / element
/// content boundaries), so element-order `contains` checks are robust to the
/// serializer's pretty-printing. Whitespace inside attribute values or text
/// nodes is untouched.
fn squeeze_intertag_ws(xml: &str) -> String {
    let mut out = String::with_capacity(xml.len());
    let bytes = xml.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i];
        if c == b'>' {
            out.push('>');
            let mut j = i + 1;
            while j < bytes.len() && (bytes[j] as char).is_ascii_whitespace() {
                j += 1;
            }
            if j < bytes.len() && bytes[j] == b'<' {
                i = j;
                continue;
            }
        } else {
            out.push(c as char);
        }
        i += 1;
    }
    out
}

/// `stemma::api::validate(..).ok` — the opens-clean signal (no package /
/// wordprocessing / schema invariant violations). Returns the boolean and a
/// human-readable concatenation of any issues for the assertion message.
fn opens_clean(bytes: &[u8]) -> (bool, String) {
    let report = stemma::api::validate(bytes);
    let detail = report
        .issues
        .iter()
        .map(|iss| format!("[{:?}] {}", iss.code, iss.message))
        .collect::<Vec<_>>()
        .join("; ");
    (report.ok, detail)
}

