fn continuous_section_omitting_page_props_opens_clean() {
    let body = r#"<w:p><w:pPr><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:pgMar w:top="1440" w:bottom="1440" w:left="1440" w:right="1440"/></w:sectPr></w:pPr><w:r><w:t>First section with full page setup.</w:t></w:r></w:p><w:p><w:r><w:t>Continuous second section, no page props.</w:t></w:r></w:p><w:sectPr><w:type w:val="continuous"/></w:sectPr>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "§17.6.22 (ISO 29500-1 §17.6.22 / MS-OI §17.6.22 / ECMA-376 §17.6.17): a \
         continuous section may omit page-level properties (inherited), and \
         MS-OI requires only that w:type carry val; the document supplies \
         val=\"continuous\" and omits pgSz/pgMar, so Word opens it without \
         repair; validate reported: {detail}"
    );
}

